import org.springframework.core.io.FileSystemResource;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.bind.annotation.RestController;
import org.springframework.web.multipart.MultipartFile;

import java.io.File;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.util.Arrays;
import java.util.List;

@RestController
public class FileUploadController {

    private final String directory = "/path/to/public/directory/";

    private static final List<String> contentTypes = Arrays.asList(
            "image/png", "image/jpeg", "image/gif");

    @PostMapping("/upload")
    public ResponseEntity<?> handleFileUpload(@RequestParam("file") MultipartFile file) {
        if (file.isEmpty()) {
            return new ResponseEntity<>("Select a file!", HttpStatus.BAD_REQUEST);
        }

        if (!contentTypes.contains(file.getContentType())) {
            return new ResponseEntity<>("File type not supported!", HttpStatus.BAD_REQUEST);
        }

        try {
            byte[] bytes = file.getBytes();

            Path path = Paths.get(directory + file.getOriginalFilename());

            Files.write(path, bytes);

            File uploadedFile = new FileSystemResource(directory).getFile();

            String fileUrl = "/public/" + file.getOriginalFilename();

            return new ResponseEntity<>(fileUrl, HttpStatus.OK);

        } catch (IOException e) {
            return new ResponseEntity<>(HttpStatus.BAD_REQUEST);
        }
    }
}